import React, { useState, useEffect } from "react";
import axios from "axios";

const Tours = () => {
  const [tours, setTours] = useState([]);
  const [newTour, setNewTour] = useState({
    country_id: "",
    name: "",
    description: "",
    price: "",
    departure_date: "",
    return_date: "",
    available: true,
  });
  const [editingTour, setEditingTour] = useState(null);
  const [countries, setCountries] = useState([]); // For fetching countries for the dropdown

  // Decode function to handle Cyrillic characters
  function decodeUnicode(str) {
    return str.replace(/\\u([\dA-F]{4})/gi, (match, grp) => {
      return String.fromCharCode(parseInt(grp, 16));
    });
  }

  useEffect(() => {
    // Fetch tours and countries
    axios
      .get("/api/tours")
      .then((response) => {
        setTours(response.data);
      })
      .catch((err) => console.error(err));

    axios
      .get("/api/countries")
      .then((response) => {
        const decodedCountries = response.data.map((country) => ({
          ...country,
          name: decodeUnicode(country.name), // Decode country names
        }));
        setCountries(decodedCountries);
      })
      .catch((err) => console.error(err));
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setNewTour({
      ...newTour,
      [name]: value,
    });
  };

  const handleCreateTour = (e) => {
    e.preventDefault();
    axios
      .post("/api/tours", newTour)
      .then((response) => {
        setTours([...tours, response.data]);
        resetForm();
      })
      .catch((err) => console.error(err));
  };

  const handleEditTour = (tour) => {
    setEditingTour(tour);
    setNewTour(tour);
  };

  const handleUpdateTour = (e) => {
    e.preventDefault();
    axios
      .put(`/api/tours/${editingTour.id}`, newTour)
      .then((response) => {
        setTours(
          tours.map((tour) => (tour.id === editingTour.id ? response.data : tour))
        );
        resetForm();
      })
      .catch((err) => console.error(err));
  };

  const handleDeleteTour = (id) => {
    axios
      .delete(`/api/tours/${id}`)
      .then(() => setTours(tours.filter((tour) => tour.id !== id)))
      .catch((err) => console.error(err));
  };

  const resetForm = () => {
    setEditingTour(null);
    setNewTour({
      country_id: "",
      name: "",
      description: "",
      price: "",
      departure_date: "",
      return_date: "",
      available: true,
    });
  };

  return (
    <div className="form-container">
      <div className="form-card">
        <h2>{editingTour ? "Edit Tour" : "Create Tour"}</h2>
        <form onSubmit={editingTour ? handleUpdateTour : handleCreateTour}>
          <div className="input-group">
            <label>Tour Name</label>
            <input
              type="text"
              name="name"
              value={newTour.name}
              placeholder="Enter tour name"
              onChange={handleInputChange}
            />
          </div>
          <div className="input-group">
            <label>Description</label>
            <input
              type="text"
              name="description"
              value={newTour.description}
              placeholder="Enter tour description"
              onChange={handleInputChange}
            />
          </div>
          <div className="input-group">
            <label>Price</label>
            <input
              type="number"
              name="price"
              value={newTour.price}
              placeholder="Enter price"
              onChange={handleInputChange}
            />
          </div>
          <div className="input-group">
            <label>Departure Date</label>
            <input
              type="date"
              name="departure_date"
              value={newTour.departure_date}
              onChange={handleInputChange}
            />
          </div>
          <div className="input-group">
            <label>Return Date</label>
            <input
              type="date"
              name="return_date"
              value={newTour.return_date}
              onChange={handleInputChange}
            />
          </div>
          <div className="input-group">
            <label>Available</label>
            <select
              name="available"
              value={newTour.available}
              onChange={handleInputChange}
            >
              <option value={true}>Yes</option>
              <option value={false}>No</option>
            </select>
          </div>
          <div className="input-group">
            <label>Country</label>
            <select
              name="country_id"
              value={newTour.country_id}
              onChange={handleInputChange}
            >
              <option value="">Select a Country</option>
              {countries.map((country) => (
                <option key={country.id} value={country.id}>
                  {country.name}
                </option>
              ))}
            </select>
          </div>

          <button type="submit" className="submit-btn">
            {editingTour ? "Update Tour" : "Create Tour"}
          </button>
        </form>
      </div>

      <div className="countries-table">
        <div style={{ overflowX: "auto", overflowY: "auto" }}>
          <table>
            <thead>
              <tr>
                <th>Tour Name</th>
                <th>Country</th>
                <th>Price</th>
                <th>Departure Date</th>
                <th>Return Date</th>
                <th>Available</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {tours.map((tour) => (
                <tr key={tour.id}>
                  <td>{tour.name}</td>
                  <td>{tour.Country ? tour.Country.name : "N/A"}</td>
                  <td>{tour.price}</td>
                  <td>{tour.departure_date}</td>
                  <td>{tour.return_date}</td>
                  <td>{tour.available ? "Yes" : "No"}</td>
                  <td className="action-buttons">
                    <button
                      className="action-btn"
                      onClick={() => handleEditTour(tour)}
                    >
                      Edit
                    </button>
                    <button
                      className="action-btn"
                      onClick={() => handleDeleteTour(tour.id)}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Tours;
